import 'slick-carousel'

export default () => {

  $('.partners').slick({
    speed: 2000,
    autoplay: true,
    useCSS: false,
    autoplaySpeed: 0,
    centerMode: true,
    slidesToShow: 1,
    slidesToScroll: 1,
    variableWidth: true,
    initialSlide: 1,
    arrows: false,
    pauseOnFocus: false,
    pauseOnHover: true,
    buttons: false
  });

  $('.how__images').each(function() {
    $(this).slick({
      slidesToShow: 1,
      slidesToScroll: 1,
      fade: true,
      speed: 4000,
      autoplaySpeed: 0,
      autoplay: true,
      asNavFor: '.how__list',
      arrows: false
    });
  });

  $('.news-gallery').each(function() {
    $(this).slick({
      slidesToShow: 1,
      slidesToScroll: 1,
      prevArrow: `<button type="button" class="slick-prev first-arrow">
                  <svg width="38" height="38" viewBox="0 0 38 38" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M24.7137 30.4286L13.2852 19L24.7137 7.57141" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                  </svg>
                  </button>`,
      nextArrow: `<button type="button" class="slick-next first-arrow">
                  <svg width="38" height="38" viewBox="0 0 38 38" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M13.2852 7.57141L24.7137 19L13.2852 30.4286" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                  </svg>
                  </button>`,
      fade: true,
      responsive: [
        {
          breakpoint: 1250,
          settings: {
            arrows: false,
            dots: true
          }
        }
      ]
    });
  });

  $('.how__list').each(function() {
    $(this).slick({
      slidesToShow: 6,
      slidesToScroll: 1,
      vertical: true,
      focusOnSelect: true,
      adaptiveHeight: true,
      asNavFor: '.how__images',
      arrows: false,
      responsive: [
        {
          breakpoint: 1250,
          settings: {
            vertical: false,
            slidesToShow: 2
          }
        },
        {
          breakpoint: 767,
          settings: {
            vertical: false,
            slidesToShow: 1
          }
        }
      ]
    });
  });



  $('.how__list')
  .on('afterChange init', function(event, slick, direction){
      // console.log('afterChange/init', event, slick, slick.$slides);
      // remove all prev/next
      slick.$slides.removeClass('active').removeClass('nextSlide');
      slick.$slides.removeClass('line').removeClass('nextSlide');

      // find current slide
      for (var i = 0; i < slick.$slides.length; i++)
      {
          if ($(slick.$slides[0]).hasClass('slick-current')) {
            $(slick.$slides[0]).addClass('line');
              break;
          }
          if ($(slick.$slides[1]).hasClass('slick-current')) {
            $(slick.$slides[0]).addClass('active');
            $(slick.$slides[0]).addClass('line');
            $(slick.$slides[1]).addClass('line');
              break;
          }
          if ($(slick.$slides[2]).hasClass('slick-current')) {
            $(slick.$slides[0]).addClass('active');
            $(slick.$slides[1]).addClass('active');
            $(slick.$slides[0]).addClass('line');
            $(slick.$slides[1]).addClass('line');
            $(slick.$slides[2]).addClass('line');
              break;
          }
          if ($(slick.$slides[3]).hasClass('slick-current')) {
            $(slick.$slides[0]).addClass('active');
            $(slick.$slides[1]).addClass('active');
            $(slick.$slides[2]).addClass('active');
            $(slick.$slides[0]).addClass('line');
            $(slick.$slides[1]).addClass('line');
            $(slick.$slides[2]).addClass('line');
            $(slick.$slides[3]).addClass('line');
              break;
          }
          if ($(slick.$slides[4]).hasClass('slick-current')) {
            $(slick.$slides[0]).addClass('active');
            $(slick.$slides[1]).addClass('active');
            $(slick.$slides[2]).addClass('active');
            $(slick.$slides[3]).addClass('active');
            $(slick.$slides[0]).addClass('line');
            $(slick.$slides[1]).addClass('line');
            $(slick.$slides[2]).addClass('line');
            $(slick.$slides[3]).addClass('line');
              break;
          }
      }
    }
  )
  .on('beforeChange', function(event, slick) {
      // optional, but cleaner maybe
      // remove all prev/next
      slick.$slides.removeClass('prevSlide').removeClass('nextSlide');
  })


  $('.reviews__slider').each(function() {
    const arrowContainer = $(this).siblings('.reviews__col').find('.reviews__control');
    $(this).slick({
      slidesToShow: 2,
      slidesToScroll: 1,
      appendArrows: arrowContainer,
      infinite: false,
      prevArrow: `<button type="button" class="slick-prev first-arrow">
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M21 12H3M3 12L10 5M3 12L10 19" stroke="#DD6B3A" stroke-linecap="square" stroke-linejoin="round"/>
                  </svg>
                  </button>`,
      nextArrow: `<button type="button" class="slick-next first-arrow">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M3 12H21M21 12L14 19M21 12L14 5" stroke="#DD6B3A" stroke-linecap="square" stroke-linejoin="round"/>
                    </svg>
                  </button>`,
      responsive: [
        {
          breakpoint: 1250,
          settings: {
            arrows: false,
            dots: true
          }
        },
        {
          breakpoint: 1250,
          settings: {
            slidesToShow: 1,
            arrows: false,
            dots: true
          }
        }
      ]
    });
  });

  var slideCount = $('.reviews__slider .slick-slide').length;

  if (slideCount < 3) {
    $('.reviews__slider').addClass('no-slider');
  }
  if ($(window).width() < 1250) {
    $('.add-partners__list').slick({
      speed: 2000,
      autoplay: true,
      useCSS: false,
      autoplaySpeed: 0,
      centerMode: true,
      rows: 3,
      slidesToShow: 1,
      slidesToScroll: 1,
      variableWidth: true,
      initialSlide: 1,
      arrows: false,
      pauseOnFocus: false,
      pauseOnHover: true,
      buttons: false
    });
  }

  $('.examples__list').each(function() {
    if ($(window).width() < 1250) {
      $(this).slick({
        slidesToShow: 1,
        slidesToScroll: 1,
        dots: true,
        arrows: false
      });
    }
  });

  $('.news-slider .news__list').each(function() {
    if ($(window).width() < 1250) {
      $(this).slick({
        slidesToShow: 2,
        slidesToScroll: 1,
        dots: true,
        arrows: false,
        infinite: false,
        responsive: [
          {
            breakpoint: 767,
            settings: {
              slidesToShow: 1,
              arrows: false,
              dots: true
            }
          }
        ]
      });
    }
  });

  $('.why__three-columns').each(function() {
    if ($(window).width() < 1250) {
      $(this).slick({
        slidesToShow: 1,
        slidesToScroll: 1,
        dots: true,
        arrows: false,
        infinite: false,
        responsive: [
          {
            breakpoint: 767,
            settings: {
              slidesToShow: 1,
              arrows: false,
              dots: true
            }
          }
        ]
      });
    }
  });

  $('.what__list').each(function() {
    if ($(window).width() < 1250) {
      $(this).slick({
        slidesToShow: 2,
        slidesToScroll: 1,
        dots: true,
        arrows: false,
        infinite: false,
        responsive: [
          {
            breakpoint: 1023,
            settings: {
              slidesToShow: 1,
              arrows: false,
              dots: true
            }
          }
        ]
      });
    }
  });

}



