        var D = calculator.find('.d-years').val();

        function func(x) {
            return (PV / P) - ((Math.pow(1+x, -D) - 1) / (1 - Math.pow(1+x, 1/12)));
        }

        function derivative(x) {
            return (Math.pow(1+x, -D) * D - Math.pow(1+x, 1/12) * (Math.pow(1+x, -D) - 1) * (1/12)) / Math.pow(1 - Math.pow(1+x, 1/12), 2);
        }

        function derivative2(x) {
            var val1 = - (-1 + Math.pow(1+x, -D)) / (12 * Math.pow(1 + x, 11/12) * Math.pow(-1 + Math.pow(1+x, 1/12), 2));
            var val2 = - D / (Math.pow(1+x, D+1) * (-1 + Math.pow(1+x, 1/12)));
            return val1 + val2;
        }

        function newtonMethod(x) {
            var guess = x;
            var maxIterations = 1000000;
            var epsilon = 0.000001;
            var iteration = 0;
            var error = 1;

            while (error > epsilon && iteration < maxIterations) {
                var f = func(guess);
                var fPrime = derivative2(guess);
                var nextGuess = guess - f / fPrime;
                error = Math.abs(nextGuess - guess);
                guess = nextGuess;
                iteration += 1;
            }

            return guess;
        }

